package cjfw.wms.cm.controller;

import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestPart;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import cjfw.core.excel.ExcelDownload;
import cjfw.core.excel.ExcelUpload;
import cjfw.core.model.ApiResult;
import cjfw.wms.cm.service.CmExcelService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

@RestController
@RequiredArgsConstructor
@Slf4j
@RequestMapping("api/cm/excel")
public class CmExcelController {

	private final CmExcelService cmExcelService;

	/**
	 * 엑셀업로드(Content-Type: multipart/form-data)
	 */
	@PostMapping(value = "/v1.0/excelUpload", consumes = { MediaType.MULTIPART_FORM_DATA_VALUE, MediaType.APPLICATION_JSON_VALUE })
	public ApiResult<ExcelUpload> excelUpload(@RequestPart(value = "file") MultipartFile file, @RequestPart(value = "params") ExcelUpload excel) {
		ExcelUpload upload = cmExcelService.uploadExcel(file, excel);
		return ApiResult.createResult(upload);
	}
	
	/**
	 * 엑셀다운로드
	 */
	@PostMapping("/v1.0/download/{type}")
	public void downloadGridDataFile(@PathVariable String type, @RequestBody ExcelDownload excelDownload, HttpServletRequest request, HttpServletResponse response) {
		// API 추가 파라메터가 필요한 경우 ExcelDownload 대신 업무 별 ReqDto 생성 후 사용
		excelDownload.setExtension(type);
		cmExcelService.downloadExcel(request, response, excelDownload);

		/** [MPA 참조]
		 * Request URL: http://dev.ictdev.cj.net/comfunc/func/excel/download/xlsx?logProgCd=&logDownCount=1&logGridPid=divGrdMst
		 * Request Method: POST
		 *
		 * > application/x-www-form-urlencoded
		 * extension: xlsx
		 * filename: ExcelDownloadSample_20220618195610
		 * data: 
		 * param:
		 *
		 *
		 */
	}

}
